class Solution:
    def minElement(self, nums: List[int]) -> int:
        sums = []
        for num in nums:
            digit_sum = sum(int(d) for d in str(num))
            sums.append(digit_sum)
        return min(sums)

class Solution:
    def maximumTotalSum(self, maximumHeight: List[int]) -> int:
        maximumHeight.sort(reverse=True)
        prev = float('inf')
        total = 0
        for h in maximumHeight:
            current = min(h, prev - 1)
            if current <= 0:
                return -1
            total += current
            prev = current
        return total

class Solution:
    def validSequence(self, word1: str, word2: str) -> List[int]:
        n = len(word2)
        m = len(word1)
        if m < n:
            return []

        res = []
        prev = -1
        mismatches = 0
        for k in range(n):
            for i in range(prev + 1, m):
                if word1[i] == word2[k]:
                    allowed_mismatches = 1 - mismatches
                    start1 = i + 1
                    start2 = k + 1
                    if self.can_match_with_mismatches(start1, start2, allowed_mismatches):
                        res.append(i)
                        prev = i
                        break
                else:
                    if mismatches == 0:
                        start1 = i + 1
                        start2 = k + 1
                        if self.can_match(start1, start2):
                            res.append(i)
                            prev = i
                            mismatches += 1
                            break
            else:
                return []
        return res

    def can_match(self, start1, start2):
        i = start1
        j = start2
        while i < len(word1) and j < len(word2):
            if word1[i] == word2[j]:
                j += 1
            i += 1
        return j == len(word2)

    def can_match_with_mismatches(self, start1, start2, allowed_mismatches):
        i = start1
        j = start2
        m = allowed_mismatches
        while i < len(word1) and j < len(word2):
            if word1[i] == word2[j]:
                j += 1
            else:
                if m > 0:
                    m -= 1
                else:
                    return False
            i += 1
        return j == len(word2)

class Solution:
    def minStartingIndex(self, s: str, pattern: str) -> int:
        n = len(s)
        m = len(pattern)
        for i in range(n - m + 1):
            count = 0
            for k in range(m):
                if s[i + k] != pattern[k]:
                    count += 1
                    if count > 1:
                        break
            if count <= 1:
