from collections import defaultdict, deque

def max_bipartite_matching(graph, left_nodes):
    match_to = {right: None for right in left_nodes}
    result = 0

    def dfs(u, visited):
        for v in graph[u]:
            if not visited[v]:
                visited[v] = True
                if match_to[v] is None or dfs(match_to[v], visited):
                    match_to[v] = u
                    return True
        return False

    for u in left_nodes:
        visited = {right: False for right in left_nodes}
        if dfs(u, visited):
            result += 1
    return result

def main():
    N = int(input())
    edges = [input().strip() for _ in range(N)]

    # Build directed adjacency list
    adjacency_list_directed = defaultdict(list)
    start_char_to_edges = defaultdict(list)

    for edge in edges:
        start = edge[0]
        end = edge[1]
        start_char_to_edges[start].append(edge)

    for e in edges:
        start_e = e[0]
        end_e = e[1]
        # Find all edges that start with end_e
        for f in start_char_to_edges[end_e]:
            if f != e:  # exclude self loops
                adjacency_list_directed[e].append(f)

    # Build undirected adjacency list
    undirected_adj = defaultdict(list)
    for e in edges:
        for f in adjacency_list_directed[e]:
            undirected_adj[e].append(f)
            undirected_adj[f].append(e)

    # Find connected components
    visited = set()
    components = []
    for e in edges:
        if e not in visited:
            q = deque([e])
            visited.add(e)
            component = []
            while q:
                node = q.popleft()
                component.append(node)
                for neighbor in undirected_adj[node]:
                    if neighbor not in visited:
                        visited.add(neighbor)
                        q.append(neighbor)
            components.append(component)

    total = 0
    for component in components:
        # Build bipartite graph
        graph_bipartite = defaultdict(list)
        for e in component:
            for f in adjacency_list_directed[e]:
                if f in component and f != e:
                    graph_bipartite[e].append(f)
        # Compute maximum matching
        max_match = max_bipartite_matching(graph_bipartite, component)
        # Add the number of paths for this component
        total += len(component) - max_match

    print(total)

