        total = 0
        for A, P, B, Q in processes:
            min_cost = float('inf')
            # Only S
            s_needed = (K + A - 1) // A
            cost_s = s_needed * P
            min_cost = min(min_cost, cost_s)
            # Only T
            t_needed = (K + B - 1) // B
            cost_t = t_needed * Q
            min_cost = min(min_cost, cost_t)
            # Try t from 0 to B
            for t in range(0, B + 1):
                remaining = K - t * B
                if remaining <= 0:
                    current_cost = t * Q
                    if current_cost < min_cost:
                        min_cost = current_cost
                else:
                    s_needed = (remaining + A - 1) // A
                    current_cost = t * Q + s_needed * P
                    if current_cost < min_cost:
                        min_cost = current_cost
            # Try s from 0 to A
            for s in range(0, A + 1):
                remaining = K - s * A
                if remaining <= 0:
                    current_cost = s * P
                    if current_cost < min_cost:
                        min_cost = current_cost
                else:
                    t_needed = (remaining + B - 1) // B
                    current_cost = s * P + t_needed * Q
                    if current_cost < min_cost:
                        min_cost = current_cost
            if min_cost == float('inf'):
                return False
            total += min_cost
            if total > X:
                return False
        return total <= X

    low = 0
