from collections import defaultdict

MOD = 998244353

def generate_valid_configs(row_str):
    W = len(row_str)
    # Initialize configurations for the first cell
    configs = []
    if row_str[0] == '1':
        configs = [(1,)]
    elif row_str[0] == '2':
        configs = [(2,)]
    elif row_str[0] == '3':
        configs = [(3,)]
    else:
        configs = [(1,), (2,), (3,)]
    for j in range(1, W):
        new_configs = []
        for config in configs:
            prev_val = config[-1]
            # Determine possible values for current cell
            if row_str[j] == '1':
                possible = [1]
            elif row_str[j] == '2':
                possible = [2]
            elif row_str[j] == '3':
                possible = [3]
            else:
                possible = [1, 2, 3]
            for val in possible:
                if val != prev_val:
                    new_config = config + (val,)
                    new_configs.append(new_config)
        configs = new_configs
    return configs

def main():
    input = sys.stdin.read
    data = input().split()
    idx = 0
    H = int(data[idx])
    idx += 1
    W = int(data[idx])
    idx += 1
    grid = []
    for _ in range(H):
        grid.append(data[idx])
        idx += 1
    # Precompute valid configurations for each row
    row_configs = []
    for row in grid:
        row_configs.append(generate_valid_configs(row))
    # Initialize DP
    dp_prev = defaultdict(int)
    for config in row_configs[0]:
        dp_prev[config] = 1
    for i in range(1, H):
        dp_curr = defaultdict(int)
        for prev_config in dp_prev:
            for curr_config in row_configs[i]:
                compatible = True
                for j in range(W):
                    if prev_config[j] == curr_config[j]:
                        compatible = False
                        break
                if compatible:
                    dp_curr[curr_config] = (dp_curr[curr_config] + dp_prev[prev_config]) % MOD
        dp_prev = dp_curr
        if not dp_prev:
            print(0)
            return
    print(sum(dp_prev.values()) % MOD)

