    for i in range(2, int(max_A**0.5) + 1):
        if spf[i] == i:
            for j in range(i*i, max_A + 1, i):
                if spf[j] == j:
                    spf[j] = i
    mu = [1]*(max_A + 1)
    for n in range(2, max_A + 1):
        x = n
        factors = {}
        is_square_free = True
        while x != 1:
            p = spf[x]
            if p in factors:
                factors[p] += 1
                if factors[p] >= 2:
                    is_square_free = False
            else:
                factors[p] = 1
            x = x // p
        if not is_square_free:
            mu[n] = 0
        else:
            mu[n] = (-1)**len(factors)

    # Precompute pow2
    pow2 = [1]*(N+2)
    for i in range(1, N+2):
        pow2[i] = (pow2[i-1] * 2) % MOD

